const initTabs=()=>{document.querySelectorAll("[data-tabs]").forEach(e=>{const t=e.querySelectorAll("[data-tabs-trigger]"),a=e.querySelectorAll("[data-tabs-panel]");t.forEach(o=>{o.addEventListener("click",()=>{const i=o.dataset.tab;t.forEach(e=>{e.classList.toggle("is-active",e===o),e.setAttribute("aria-selected",e===o?"true":"false")}),a.forEach(e=>{const t=e.dataset.tab===i;e.classList.toggle("is-active",t),e.hidden=!t}),e.dispatchEvent(new CustomEvent("tabs:change",{detail:{tab:i},bubbles:!0}))})})})};function initTooltips(){document.querySelectorAll("[data-tooltip]").forEach(e=>{e.classList.add("tooltip-wrapper");const t=e.dataset.tooltip,a=document.createElement("span");a.className="tooltip-bubble",a.textContent=t,e.appendChild(a),e.addEventListener("mouseenter",()=>a.classList.add("is-visible")),e.addEventListener("mouseleave",()=>a.classList.remove("is-visible")),e.addEventListener("focusin",()=>a.classList.add("is-visible")),e.addEventListener("focusout",()=>a.classList.remove("is-visible"))})}function initAccordion(){document.querySelectorAll("[data-accordion-trigger]").forEach(e=>{e.addEventListener("click",()=>{const t=e.closest("[data-accordion-item]"),a=(t.querySelector("[data-accordion-panel]"),t.classList.contains("is-open")),o=t.closest("[data-accordion]");o&&o.hasAttribute("data-accordion-single")&&o.querySelectorAll("[data-accordion-item].is-open").forEach(e=>{e!==t&&closeAccordionItem(e)}),a?closeAccordionItem(t):openAccordionItem(t)})})}function openAccordionItem(e){const t=e.querySelector("[data-accordion-trigger]"),a=e.querySelector("[data-accordion-panel]");e.classList.add("is-open"),t.setAttribute("aria-expanded","true"),a.hidden=!1}function closeAccordionItem(e){const t=e.querySelector("[data-accordion-trigger]"),a=e.querySelector("[data-accordion-panel]");e.classList.remove("is-open"),t.setAttribute("aria-expanded","false"),a.hidden=!0}document.addEventListener("DOMContentLoaded",()=>{initTabs(),initTooltips(),initAccordion()});